function findPeak(nums) {
  // Binary search.
  // Compare mid with mid+1:
  //   - If nums[mid] > nums[mid+1], a peak exists in nums[0..mid].
  //   - Otherwise it exists in nums[mid+1..n-1].
  // Why? Walking 'uphill' must eventually hit a peak (the boundary is -∞).
}

solution:
// O(log n) time, O(1) space.
function findPeak(nums) {
  let lo = 0, hi = nums.length - 1;
  while (lo < hi) {
    const mid = lo + Math.floor((hi - lo) / 2);
    if (nums[mid] > nums[mid + 1]) {
      // descending slope — peak is to the LEFT (or at mid)
      hi = mid;
    } else {
      // ascending slope — peak is to the RIGHT
      lo = mid + 1;
    }
  }
  return lo;
}
